script:
{
  "@context": "https://schema.org",
  "@graph": [
    {
      "@type": "WebPage",
      "@id": "https://{{DOMAIN}}/services/silicone-render.html#webpage",
      "url": "https://{{DOMAIN}}/services/silicone-render.html",
      "name": "Silicone Render Guildford & Surrey | Cost & Application | RenderWorks",
      "description": "Silicone render in Guildford & Surrey costs £60–120/m² installed. Through-coloured, hydrophobic, self-cleaning, 25–40 year life, never needs repainting.",
      "inLanguage": "en-GB",
      "isPartOf": { "@id": "https://{{DOMAIN}}/#website" },
      "dateModified": "{{PRICE_UPDATED}}",
      "primaryImageOfPage": "https://{{DOMAIN}}/img/silicone-render-guildford.jpg",
      "breadcrumb": { "@id": "https://{{DOMAIN}}/services/silicone-render.html#breadcrumb" },
      "about": [
        { "@type": "Thing", "name": "Render (coating)", "sameAs": "https://en.wikipedia.org/wiki/Render_(coating)" },
        { "@type": "Thing", "name": "Stucco", "sameAs": "https://www.wikidata.org/wiki/Q183008" },
        { "@type": "Thing", "name": "Silicone", "sameAs": "https://www.wikidata.org/wiki/Q161519" }
      ],
      "mentions": [
        { "@type": "Thing", "name": "External wall insulation", "sameAs": "https://www.wikidata.org/wiki/Q5421400" },
        { "@type": "Thing", "name": "Thermal insulation", "sameAs": "https://www.wikidata.org/wiki/Q193540" },
        { "@type": "Place", "name": "Guildford", "sameAs": "https://www.wikidata.org/wiki/Q651299" },
        { "@type": "Place", "name": "Surrey", "sameAs": "https://www.wikidata.org/wiki/Q23202" }
      ]
    },

    {
      "@type": "Service",
      "@id": "https://{{DOMAIN}}/services/silicone-render.html#service",
      "serviceType": "Silicone render application",
      "name": "Silicone Render Installation",
      "description": "Supply and application of through-coloured silicone render (3–5 mm thin-coat) on external walls across Guildford and Surrey, including base coat, alkali-resistant mesh, beads, primer and topcoat.",
      "category": "Rendering / external wall finishing",
      "provider": { "@id": "https://{{DOMAIN}}/#localbusiness" },
      "areaServed": [
        { "@type": "City", "name": "Guildford", "sameAs": "https://www.wikidata.org/wiki/Q651299" },
        { "@type": "AdministrativeArea", "name": "Surrey", "sameAs": "https://www.wikidata.org/wiki/Q23202" }
      ],
      "offers": {
        "@type": "Offer",
        "priceCurrency": "GBP",
        "priceSpecification": {
          "@type": "UnitPriceSpecification",
          "price": "60.00-120.00",
          "priceCurrency": "GBP",
          "unitText": "per square metre installed",
          "valueAddedTaxIncluded": false
        },
        "availabilityStarts": "{{PRICE_UPDATED}}"
      },
      "hasOfferCatalog": {
        "@type": "OfferCatalog",
        "name": "Render systems",
        "itemListElement": [
          { "@type": "Offer", "itemOffered": { "@type": "Service", "name": "Monocouche render" } },
          { "@type": "Offer", "itemOffered": { "@type": "Service", "name": "K-Rend & Weber systems" } },
          { "@type": "Offer", "itemOffered": { "@type": "Service", "name": "External wall insulation" } }
        ]
      }
    },

    {
      "@type": ["LocalBusiness", "HomeAndConstructionBusiness"],
      "@id": "https://{{DOMAIN}}/#localbusiness",
      "name": "RenderWorks",
      "url": "https://{{DOMAIN}}/",
      "telephone": "+44-1483-000000",
      "email": "hello@{{DOMAIN}}",
      "priceRange": "££",
      "image": "https://{{DOMAIN}}/img/renderworks-team.jpg",
      "address": {
        "@type": "PostalAddress",
        "streetAddress": "{{NAP_ADDRESS}}",
        "addressLocality": "Guildford",
        "addressRegion": "Surrey",
        "postalCode": "{{POSTCODE}}",
        "addressCountry": "GB"
      },
      "geo": { "@type": "GeoCoordinates", "latitude": "51.2362", "longitude": "-0.5704" },
      "areaServed": { "@type": "GeoCircle", "geoMidpoint": { "@type": "GeoCoordinates", "latitude": "51.2362", "longitude": "-0.5704" }, "geoRadius": "24140" },
      "openingHoursSpecification": [
        { "@type": "OpeningHoursSpecification", "dayOfWeek": ["Monday","Tuesday","Wednesday","Thursday","Friday"], "opens": "07:30", "closes": "18:00" },
        { "@type": "OpeningHoursSpecification", "dayOfWeek": "Saturday", "opens": "08:00", "closes": "14:00" }
      ],
      "sameAs": [ "{{GBP_CID}}" ],
      "aggregateRating": {
        "@type": "AggregateRating",
        "ratingValue": "{{RATING}}",
        "reviewCount": "{{REVIEW_COUNT}}",
        "bestRating": "5"
      }
    },

    {
      "@type": "BreadcrumbList",
      "@id": "https://{{DOMAIN}}/services/silicone-render.html#breadcrumb",
      "itemListElement": [
        { "@type": "ListItem", "position": 1, "name": "Home", "item": "https://{{DOMAIN}}/" },
        { "@type": "ListItem", "position": 2, "name": "Services", "item": "https://{{DOMAIN}}/#services" },
        { "@type": "ListItem", "position": 3, "name": "Silicone Render", "item": "https://{{DOMAIN}}/services/silicone-render.html" }
      ]
    },

    {
      "@type": "FAQPage",
      "@id": "https://{{DOMAIN}}/services/silicone-render.html#faq",
      "mainEntity": [
        { "@type": "Question", "name": "How much does silicone render cost per m²?",
          "acceptedAnswer": { "@type": "Answer", "text": "Silicone render costs £60–£120/m² installed in Surrey, including scaffold, mesh, base coat and through-coloured topcoat. Hacking off old render adds roughly 15–20%." } },
        { "@type": "Question", "name": "Is silicone render worth the extra cost over acrylic?",
          "acceptedAnswer": { "@type": "Answer", "text": "Silicone render is breathable and self-cleaning; acrylic render is neither. On most UK homes the silicone topcoat resists algae and damp better, which is why it is specified despite a higher cost per m²." } },
        { "@type": "Question", "name": "Can silicone render be applied over pebbledash?",
          "acceptedAnswer": { "@type": "Answer", "text": "Yes, if the pebbledash is sound and well-bonded. Loose, hollow or cracked pebbledash is hacked off first. Bond is verified by tap-testing at survey." } },
        { "@type": "Question", "name": "How long does silicone render take to apply?",
          "acceptedAnswer": { "@type": "Answer", "text": "A typical semi-detached house takes 5–10 working days including scaffold, prep and coats, weather-dependent, as application needs 5–30 °C and dry cure conditions." } },
        { "@type": "Question", "name": "Does silicone render need repainting?",
          "acceptedAnswer": { "@type": "Answer", "text": "No. Silicone render is through-coloured, so it is never painted. Maintenance is an occasional rinse; service life is 25–40 years." } }
      ]
    }
  ]
}
